42	  type axi_ms_r is record
43	    -- Read address channel			                             
44	    arid     : std_logic_vector;        -- Read address ID. This signal is the identification tag for the read address group of signals.
45	    araddr   : std_logic_vector;        -- Read address. This signal indicates the initial address of a read burst transaction.
46	    arlen    : std_logic_vector(7 downto 0); -- Burst length. The burst length gives the exact number of transfers in a burst
47	    arsize   : std_logic_vector(2 downto 0); -- Burst size. This signal indicates the size of each transfer in the burst
48	    arburst  : std_logic_vector(1 downto 0); -- Burst type. The burst type and the size information, determine how the address for each transfer within the burst is calculated.
49	    arlock   : std_logic;               -- Lock type. Provides additional information about the atomic characteristics of the transfer.
50	    arcache  : std_logic_vector(3 downto 0); -- Memory type. This signal indicates how transactions are required to progress through a system.
51	    arprot   : std_logic_vector(2 downto 0); -- Protection type. This signal indicates the privilege and security level of the transaction, and whether the transaction is a data access or an instruction access.
52	    arqos    : std_logic_vector(3 downto 0); -- Quality of Service, QoS identifier sent for each read transaction.
53	    arregion : std_logic_vector(3 downto 0); -- Region identifier. Permits a single physical interface on a slave to be used for multiple logical interfaces.
54	    aruser   : std_logic_vector;        -- Optional User-defined signal in the read address channel.
55	    arvalid  : std_logic;               -- Write address valid. This signal indicates that the channel is signaling valid read address and control information.
56	    -- Read data channel			                             
57	    rready   : std_logic;               -- Read ready. This signal indicates that the master can accept the read data and response information.
58	    -- Write address channel                                     
59	    awid     : std_logic_vector;        -- Write Address ID
60	    awaddr   : std_logic_vector;        -- Write address
61	    awlen    : std_logic_vector(7 downto 0); -- Burst length. The burst length gives the exact number of transfers in a burst
62	    awsize   : std_logic_vector(2 downto 0); -- Burst size. This signal indicates the size of each transfer in the burst
63	    awburst  : std_logic_vector(1 downto 0); -- Burst type. The burst type and the size information, determine how the address for each transfer within the burst is calculated.
64	    awlock   : std_logic;               -- Lock type. Provides additional information about the atomic characteristics of the transfer.
65	    awcache  : std_logic_vector(3 downto 0); -- Memory type. This signal indicates how transactions are required to progress through a system.
66	    awprot   : std_logic_vector(2 downto 0); -- Protection type. This signal indicates the privilege and security level of the transaction, and whether the transaction is a data access or an instruction access.
67	    awqos    : std_logic_vector(3 downto 0); -- Quality of Service, QoS identifier sent for each write transaction.
68	    awregion : std_logic_vector(3 downto 0); -- Region identifier. Permits a single physical interface on a slave to be used for multiple logical interfaces.
69	    awuser   : std_logic_vector;        -- Optional User-defined signal in the write address channel.
70	    awvalid  : std_logic;               -- Write address valid. This signal indicates that the channel is signaling valid write address and control information.
71	    -- Write data channel                                        
72	    wdata    : std_logic_vector;        -- Write Data
73	    wstrb    : std_logic_vector;        -- Write strobes. This signal indicates which byte lanes hold valid data. There is one write strobe bit for each eight bits of the write data bus.
74	    wlast    : std_logic;               -- Write last. This signal indicates the last transfer in a write burst.
75	    wuser    : std_logic_vector;        -- Optional User-defined signal in the write data channel.
76	    wvalid   : std_logic;               -- Write valid. This signal indicates that valid write data and strobes are available.
77	    -- Write response channel                                    
78	    bready   : std_logic;
79	  end record;
80	
81	  type axi_sm_r is record
82	    -- Read address channel			                             
83	    arready : std_logic;                -- Read address ready. This signal indicates that the slave is ready to accept an address and associated control signals.
84	    -- Read data channel			                             
85	    rid     : std_logic_vector;         -- Read ID tag. This signal is the identification tag for the read data group of signals generated by the slave.
86	    rdata   : std_logic_vector;         -- Read Data
87	    rresp   : std_logic_vector(1 downto 0); -- Read response. This signal indicates the status of the read transfer.
88	    rlast   : std_logic;                -- Read last. This signal indicates the last transfer in a read burst.
89	    ruser   : std_logic_vector;         -- Optional User-defined signal in the read address channel.
90	    rvalid  : std_logic;                -- Read valid. This signal indicates that the channel is signaling the required read data.
91	    -- Write address channel                                     
92	    awready : std_logic;                -- Write address ready. This signal indicates that the slave is ready to accept an address and associated control signals.
93	    -- Write data channel                                        
94	    wready  : std_logic;                -- Write ready. This signal indicates that the slave can accept the write data.
95	    -- Write response channel                                    
96	    bid     : std_logic_vector;         -- Response ID tag. This signal is the ID tag of the write response.
97	    bresp   : std_logic_vector(1 downto 0); -- Write response. This signal indicates the status of the write transaction.
98	    buser   : std_logic_vector;         -- Optional User-defined signal in the write response channel.
99	    bvalid  : std_logic;                -- Write response valid. This signal indicates that the channel is signaling a valid write response.
100	  end record;
