339	  function decimal_string_to_unsigned(decimal_string  : string;
340	                                      wanted_bitwidth : positive
341	                                     ) return unsigned is
342	    variable tmp_unsigned    : unsigned(wanted_bitwidth - 1 downto 0) := (others => '0');
343	    variable character_value : integer;
344	  begin
345	    for string_pos in decimal_string'range loop
346	      case decimal_string(string_pos) is
347	        when '0'    => character_value := 0;
348	        when '1'    => character_value := 1;
349	        when '2'    => character_value := 2;
350	        when '3'    => character_value := 3;
351	        when '4'    => character_value := 4;
352	        when '5'    => character_value := 5;
353	        when '6'    => character_value := 6;
354	        when '7'    => character_value := 7;
355	        when '8'    => character_value := 8;
356	        when '9'    => character_value := 9;
357	        when others => report ("decimal_string_to_unsigned: Illegal number") severity failure;
358	      end case;
359	      tmp_unsigned := resize(tmp_unsigned * 10, wanted_bitwidth);
360	      tmp_unsigned := tmp_unsigned + character_value;
361	    end loop;
362	    return tmp_unsigned;
363	  end function decimal_string_to_unsigned;
