467	  procedure axi_master_init(signal ms : out axi_ms_r) is
468	  begin
469	    ms.awid     <= std_logic_vector(to_unsigned(0, ms.awid'length));
470	    ms.awaddr   <= std_logic_vector(to_unsigned(0, ms.awaddr'length));
471	    ms.awlen    <= (others => '0');
472	    ms.awsize   <= std_logic_vector(to_unsigned(0, ms.awsize'length));
473	    ms.awburst  <= "01";
474	    ms.awvalid  <= '0';
475	    ms.awlock   <= '0';
476	    ms.awcache  <= (others => '0');
477	    ms.awprot   <= (others => '0');
478	    ms.awqos    <= (others => '0');
479	    ms.awregion <= (others => '0');
480	    ms.awuser   <= std_logic_vector(to_unsigned(0, ms.awuser'length));
481	    ms.arid     <= std_logic_vector(to_unsigned(0, ms.arid'length));
