528	    ms.awid    <= std_logic_vector(to_unsigned(0, ms.awid'length));
529	    ms.awaddr  <= std_logic_vector(to_unsigned(address, ms.awaddr'length));
530	    ms.awlen   <= (others => '0');
531	    ms.awsize  <= std_logic_vector(to_unsigned(log2(ms.wstrb'length), ms.awsize'length));
532	    ms.awburst <= "01";
533	    ms.awvalid <= '1';
534	    -- wait for address accepted
535	    wait until rising_edge(clk) and sm.awready = '1';
