594	  procedure axi_single_read(address    : in integer;
595	                            value      : out integer;
596	                            signal ms  : out axi_ms_r;
597	                            signal sm  : in axi_sm_r;
598	                            signal clk : in std_logic;
599	                            msb        : in natural := 31;
600	                            lsb        : in natural := 0;
601	                            sex        : in boolean := false) is
602	    variable valueStdlv : std_logic_vector(ms.wdata'length - 1 downto 0);
603	  begin
604	    -- synchronize
605	    wait until rising_edge(clk);
606	    -- Signal write
607	    ms.arid                        <= std_logic_vector(to_unsigned(0, ms.awid'length));
608	    ms.araddr                      <= std_logic_vector(to_unsigned(address, ms.awaddr'length));
609	    ms.arlen                       <= (others => '0');
610	    ms.arsize                      <= std_logic_vector(to_unsigned(log2(ms.wstrb'length), ms.awsize'length));
611	    ms.arburst                     <= "01";
612	    ms.arvalid                     <= '1';
613	    -- wait for address accepted
614	    wait until rising_edge(clk) and sm.arready = '1';
615	    ms.arvalid                     <= '0';
616	    ms.rready                      <= '1';
617	    -- wait for data transmitted
618	    wait until rising_edge(clk) and sm.rvalid = '1';
619	    ms.rready                      <= '0';
620	    -- Mask and correctly shift value
621	    valueStdlv                     := sm.rdata;
622	    valueStdlv(msb - lsb downto 0) := valueStdlv(msb downto lsb);
623	    if sex then
624	      valueStdlv(ms.wdata'length - 1 downto msb - lsb + 1) := (others => valueStdlv(msb));
625	    else
626	      valueStdlv(ms.wdata'length - 1 downto msb - lsb + 1) := (others => '0');
627	    end if;
628	    value                          := to_integer(signed(valueStdlv));
629	    StdlvCompareStdlv(xRESP_OKAY_c, sm.rresp, "axi_single_read(): received negative response!");
630	  end procedure;
