767	  procedure axi_apply_wd_burst(Beats        : in natural;
768	                               DataStart    : in natural;
769	                               DataIncr     : in natural;
770	                               WstrbFirst   : in std_logic_vector;
771	                               WstrbLast    : in std_logic_vector;
772	                               signal ms    : out axi_ms_r;
773	                               signal sm    : in axi_sm_r;
774	                               signal aclk  : in std_logic;
775	                               VldLowCycles : in integer := 0) is
776	    variable DataCnt_v   : natural;
777	    variable DataStdlv_v : std_logic_vector(ms.wdata'range);
778	  begin
779	    ms.wvalid <= '1';
780	    DataCnt_v := DataStart;
781	    for beat in 1 to Beats loop
782	      -- last transfer
783	      if beat = Beats then
784	        ms.wlast <= '1';
785	        ms.wstrb <= WstrbLast;
786	      elsif beat = 1 then
787	        ms.wstrb <= WstrbFirst;
788	      else
789	        ms.wstrb <= std_logic_vector(to_signed(-1, ms.wstrb'length));
790	      end if;
791	      -- Apply Data
792	      DataStdlv_v := std_logic_vector(to_unsigned(DataCnt_v, DataStdlv_v'length));
793	      ms.wdata    <= DataStdlv_v;
794	      wait until rising_edge(aclk) and sm.wready = '1';
795	      DataCnt_v   := DataCnt_v + DataIncr;
796	      -- Low cycles if required
797	      if not (beat = Beats) then
798	        for lc in 1 to VldLowCycles loop
799	          ms.wvalid <= '0';
800	          wait until rising_edge(aclk);
801	        end loop;
802	        ms.wvalid <= '1';
803	      end if;
804	    end loop;
805	    axi_master_init(ms);
806	  end procedure;
