820	    variable DataStdlv_v    : std_logic_vector(ms.wdata'range);
821	  begin
822	    ms.wvalid <= '1';
823	    case Base is
824	      when 10 =>
825	        DataCntSign_v  := decimal_string_to_signed(DataStart, ms.wdata'length);
826	        DataIncrSign_v := decimal_string_to_signed(DataIncr, ms.wdata'length);
827	      when 16 =>
828	        DataCntSign_v  := hex_string_to_signed(DataStart, ms.wdata'length);
829	        DataIncrSign_v := hex_string_to_signed(DataIncr, ms.wdata'length);
830	      when others =>
831	        report "Procedure axi_apply_wd_burst: unsupported base value" severity failure;
832	    end case;
833	    for beat in 1 to Beats loop
834	      -- last transfer
835	      if beat = Beats then
836	        ms.wlast <= '1';
837	        ms.wstrb <= WstrbLast;
838	      elsif beat = 1 then
839	        ms.wstrb <= WstrbFirst;
840	      else
841	        ms.wstrb <= std_logic_vector(to_signed(-1, ms.wstrb'length));
842	      end if;
843	      -- Apply Data
844	      DataStdlv_v   := std_logic_vector(DataCntSign_v);
845	      ms.wdata      <= DataStdlv_v;
846	      wait until rising_edge(aclk) and sm.wready = '1';
