850	      if not (beat = Beats) then
851	        for lc in 1 to VldLowCycles loop
852	          ms.wvalid <= '0';
853	          wait until rising_edge(aclk);
854	        end loop;
855	        ms.wvalid <= '1';
856	      end if;
857	    end loop;
858	    axi_master_init(ms);
