915	  procedure axi_expect_wd_burst(Beats        : in natural;
916	                                DataStart    : in natural;
917	                                DataIncr     : in natural;
918	                                WstrbFirst   : in std_logic_vector;
919	                                WstrbLast    : in std_logic_vector;
920	                                signal ms    : in axi_ms_r;
921	                                signal sm    : out axi_sm_r;
922	                                signal aclk  : in std_logic;
923	                                RdyLowCycles : in integer := 0) is
924	    variable DataCnt_v   : natural;
925	    variable DataStdlv_v : std_logic_vector(ms.wdata'range);
926	  begin
927	    sm.wready <= '1';
928	    DataCnt_v := DataStart;
929	    for beat in 1 to Beats loop
930	      wait until rising_edge(aclk) and ms.wvalid = '1';
931	      -- last transfer
932	      if beat = Beats then
933	        StdlCompare(1, ms.wlast, "WLAST not asserted at end of burst transfer");
934	        StdlvCompareStdlv(WstrbLast, ms.wstrb, "wrong WSTRB at end of burst transfer");
935	      elsif beat = 1 then
936	        StdlCompare(0, ms.wlast, "WLAST asserted at beginning of burst transfer");
937	        StdlvCompareStdlv(WstrbFirst, ms.wstrb, "wrong WSTRB at beginning of burst transfer");
938	      else
939	        StdlCompare(0, ms.wlast, "WLAST asserted in the middle of burst transfer");
940	        StdlvCompareInt(-1, ms.wstrb, "wrong WSTRB in the middle of burst transfer");
941	      end if;
942	      -- Apply Data
943	      DataStdlv_v := std_logic_vector(to_unsigned(DataCnt_v, DataStdlv_v'length));
944	      for byte in 0 to ms.wdata'length / 8 - 1 loop
945	        -- only check data that is used
946	        if ms.wstrb(byte) = '1' then
947	          StdlvCompareStdlv(DataStdlv_v(byte * 8 - 1 downto byte * 8), ms.wdata(byte * 8 - 1 downto byte * 8), "wrong WDATA during butst transfer - byte " & str(byte));
948	        end if;
949	      end loop;
950	      DataCnt_v   := DataCnt_v + DataIncr;
951	      -- Low cycles if required
952	      if not (beat = Beats) then
953	        for lc in 1 to RdyLowCycles loop
954	          sm.wready <= '0';
955	          wait until rising_edge(aclk) and ms.wvalid = '1';
956	        end loop;
957	        sm.wready <= '1';
958	      end if;
959	    end loop;
960	    sm.wready <= '0';
961	  end procedure;
962	
963	  procedure axi_expect_wd_burst(Beats        : in natural;
964	                                DataStart    : in string;
965	                                DataIncr     : in string;
966	                                Base         : in integer;
967	                                WstrbFirst   : in std_logic_vector;
968	                                WstrbLast    : in std_logic_vector;
969	                                signal ms    : in axi_ms_r;
970	                                signal sm    : out axi_sm_r;
971	                                signal aclk  : in std_logic;
972	                                RdyLowCycles : in integer := 0) is
973	    variable DataCntUnsign_v  : unsigned(ms.wdata'range);
974	    variable DataIncrUnsign_v : unsigned(ms.wdata'range);
975	    variable DataStdlv_v      : std_logic_vector(ms.wdata'range);
976	  begin
977	    sm.wready <= '1';
978	    case Base is
979	      when 10 =>
980	        DataCntUnsign_v  := decimal_string_to_unsigned(DataStart, ms.wdata'length);
981	        DataIncrUnsign_v := decimal_string_to_unsigned(DataIncr, ms.wdata'length);
982	      when 16 =>
983	        DataCntUnsign_v  := hex_string_to_unsigned(DataStart, ms.wdata'length);
984	        DataIncrUnsign_v := hex_string_to_unsigned(DataIncr, ms.wdata'length);
985	      when others =>
986	        report "Procedure axi_expect_wd_burst: unsupported base value" severity failure;
987	    end case;
988	    for beat in 1 to Beats loop
989	      wait until rising_edge(aclk) and ms.wvalid = '1';
990	      -- last transfer
991	      if beat = Beats then
992	        StdlCompare(1, ms.wlast, "WLAST not asserted at end of burst transfer");
993	        StdlvCompareStdlv(WstrbLast, ms.wstrb, "wrong WSTRB at end of burst transfer");
994	      elsif beat = 1 then
995	        StdlCompare(0, ms.wlast, "WLAST asserted at beginning of burst transfer");
996	        StdlvCompareStdlv(WstrbFirst, ms.wstrb, "wrong WSTRB at beginning of burst transfer");
997	      else
998	        StdlCompare(0, ms.wlast, "WLAST asserted in the middle of burst transfer");
999	        StdlvCompareInt(-1, ms.wstrb, "wrong WSTRB in the middle of burst transfer");
1000	      end if;
1001	      -- Apply Data
1002	      DataStdlv_v     := std_logic_vector(DataCntUnsign_v);
1003	      for byte in 0 to ms.wdata'length / 8 - 1 loop
1004	        -- only check data that is used
1005	        if ms.wstrb(byte) = '1' then
1006	          StdlvCompareStdlv(DataStdlv_v(byte * 8 - 1 downto byte * 8), ms.wdata(byte * 8 - 1 downto byte * 8), "wrong WDATA during butst transfer - byte " & str(byte));
1007	        end if;
1008	      end loop;
1009	      DataCntUnsign_v := DataCntUnsign_v + DataIncrUnsign_v;
1010	      -- Low cycles if required
1011	      if not (beat = Beats) then
1012	        for lc in 1 to RdyLowCycles loop
1013	          sm.wready <= '0';
1014	          wait until rising_edge(aclk) and ms.wvalid = '1';
1015	        end loop;
1016	        sm.wready <= '1';
1017	      end if;
1018	    end loop;
1019	    sm.wready <= '0';
1020	  end procedure;
1021	
1022	  procedure axi_apply_bresp(Response    : in std_logic_vector(1 downto 0);
1023	                            signal ms   : in axi_ms_r;
1024	                            signal sm   : out axi_sm_r;
1025	                            signal aclk : in std_logic) is
1026	  begin
1027	    sm.bvalid <= '1';
1028	    sm.bresp  <= Response;
1029	    wait until rising_edge(aclk) and ms.bready = '1';
1030	    axi_slave_init(sm);
1031	  end procedure;
1032	
1033	  procedure axi_expect_bresp(Response    : in std_logic_vector(1 downto 0);
1034	                             signal ms   : out axi_ms_r;
1035	                             signal sm   : in axi_sm_r;
1036	                             signal aclk : in std_logic) is
1037	  begin
1038	    ms.bready <= '1';
1039	    wait until rising_edge(aclk) and sm.bvalid = '1';
1040	    StdlvCompareStdlv(Response, sm.bresp, "wrong BRESP");
1041	    ms.bready <= '0';
1042	  end procedure;
1043	
1044	  procedure axi_apply_rresp_single(Data        : in std_logic_vector;
1045	                                   Response    : in std_logic_vector(1 downto 0);
1046	                                   signal ms   : in axi_ms_r;
1047	                                   signal sm   : out axi_sm_r;
1048	                                   signal aclk : in std_logic) is
1049	    constant DataInt_c : std_logic_vector(Data'length - 1 downto 0) := Data;
1050	  begin
1051	    sm.rvalid <= '1';
1052	    sm.rdata  <= DataInt_c;
1053	    sm.rresp  <= Response;
1054	    sm.rlast  <= '1';
1055	    wait until rising_edge(aclk) and ms.rready = '1';
1056	    axi_slave_init(sm);
1057	  end procedure;
1058	
1059	  procedure axi_apply_rresp_burst(Beats        : in natural;
1060	                                  DataStart    : in natural;
1061	                                  DataIncr     : in natural;
1062	                                  Response     : in std_logic_vector(1 downto 0);
1063	                                  signal ms    : in axi_ms_r;
1064	                                  signal sm    : out axi_sm_r;
1065	                                  signal aclk  : in std_logic;
1066	                                  VldLowCycles : in integer := 0) is
1067	    variable DataCnt_v   : natural;
1068	    variable DataStdlv_v : std_logic_vector(ms.wdata'range);
1069	  begin
1070	    sm.rvalid <= '1';
1071	    sm.rlast  <= '0';
1072	    DataCnt_v := DataStart;
1073	    sm.rresp  <= Response;
1074	    for beat in 1 to Beats loop
1075	      -- last transfer
1076	      if beat = Beats then
1077	        sm.rlast <= '1';
1078	      end if;
1079	      -- Apply Data
1080	      DataStdlv_v := std_logic_vector(to_unsigned(DataCnt_v, DataStdlv_v'length));
1081	      sm.rdata    <= DataStdlv_v;
1082	      wait until rising_edge(aclk) and ms.rready = '1';
1083	      DataCnt_v   := DataCnt_v + DataIncr;
1084	      -- Low cycles if required
1085	      if not (beat = Beats) then
1086	        for lc in 1 to VldLowCycles loop
1087	          sm.rvalid <= '0';
1088	          wait until rising_edge(aclk) and ms.rready = '1';
1089	        end loop;
1090	        sm.rvalid <= '1';
1091	      end if;
1092	    end loop;
1093	    axi_slave_init(sm);
1094	  end procedure;
1095	
1096	  procedure axi_apply_rresp_burst(Beats        : in natural;
1097	                                  DataStart    : in string;
1098	                                  DataIncr     : in string;
1099	                                  Base         : in integer;
1100	                                  Response     : in std_logic_vector(1 downto 0);
1101	                                  signal ms    : in axi_ms_r;
1102	                                  signal sm    : out axi_sm_r;
1103	                                  signal aclk  : in std_logic;
1104	                                  VldLowCycles : in integer := 0) is
1105	    variable DataCntUnsign_v  : unsigned(ms.wdata'range);
1106	    variable DataIncrUnsign_v : unsigned(ms.wdata'range);
1107	    variable DataStdlv_v      : std_logic_vector(ms.wdata'range);
1108	  begin
1109	    sm.rvalid <= '1';
1110	    sm.rlast  <= '0';
1111	    case Base is
1112	      when 10 =>
1113	        DataCntUnsign_v  := decimal_string_to_unsigned(DataStart, ms.wdata'length);
1114	        DataIncrUnsign_v := decimal_string_to_unsigned(DataIncr, ms.wdata'length);
1115	      when 16 =>
1116	        DataCntUnsign_v  := hex_string_to_unsigned(DataStart, ms.wdata'length);
1117	        DataIncrUnsign_v := hex_string_to_unsigned(DataIncr, ms.wdata'length);
1118	      when others =>
1119	        report "Procedure axi_apply_rresp_burst: unsupported base value" severity failure;
1120	    end case;
1121	    sm.rresp  <= Response;
1122	    for beat in 1 to Beats loop
1123	      -- last transfer
1124	      if beat = Beats then
1125	        sm.rlast <= '1';
1126	      end if;
1127	      -- Apply Data
1128	      DataStdlv_v     := std_logic_vector(DataCntUnsign_v);
1129	      sm.rdata        <= DataStdlv_v;
1130	      wait until rising_edge(aclk) and ms.rready = '1';
1131	      DataCntUnsign_v := DataCntUnsign_v + DataIncrUnsign_v;
1132	      -- Low cycles if required
1133	      if not (beat = Beats) then
1134	        for lc in 1 to VldLowCycles loop
1135	          sm.rvalid <= '0';
1136	          wait until rising_edge(aclk) and ms.rready = '1';
1137	        end loop;
1138	        sm.rvalid <= '1';
1139	      end if;
1140	    end loop;
1141	    axi_slave_init(sm);
1142	  end procedure;
1143	
1144	  procedure axi_expect_rresp_single(Data           : in std_logic_vector;
1145	                                    Response       : in std_logic_vector(1 downto 0);
1146	                                    signal ms      : out axi_ms_r;
1147	                                    signal sm      : in axi_sm_r;
1148	                                    signal aclk    : in std_logic;
1149	                                    IgnoreData     : in boolean := false;
1150	                                    IgnoreResponse : in boolean := false) is
1151	    constant DataInt_c : std_logic_vector(Data'length - 1 downto 0) := Data;
1152	  begin
1153	    ms.rready <= '1';
1154	    wait until rising_edge(aclk) and sm.rvalid = '1';
1155	    if not IgnoreResponse then
1156	      StdlvCompareStdlv(Response, sm.rresp, "wrong RRESP");
1157	    end if;
1158	    if not IgnoreData then
1159	      StdlvCompareStdlv(DataInt_c, sm.rdata, "wrong RDATA");
1160	    end if;
1161	    StdlCompare(1, sm.rlast, "wrong RLAST");
1162	    ms.rready <= '0';
1163	  end procedure;
1164	
1165	  procedure axi_expect_rresp_burst(Beats          : in natural;
1166	                                   DataStart      : in natural;
1167	                                   DataIncr       : in natural;
1168	                                   Response       : in std_logic_vector(1 downto 0);
1169	                                   signal ms      : out axi_ms_r;
1170	                                   signal sm      : in axi_sm_r;
1171	                                   signal aclk    : in std_logic;
1172	                                   IgnoreData     : in boolean := false;
1173	                                   IgnoreResponse : in boolean := false;
1174	                                   RdyLowCycles   : in integer := 0) is
1175	    variable DataCnt_v   : natural;
1176	    variable DataStdlv_v : std_logic_vector(ms.wdata'range);
1177	  begin
1178	    ms.rready <= '1';
1179	    DataCnt_v := DataStart;
1180	    for beat in 1 to Beats loop
1181	      wait until rising_edge(aclk) and sm.rvalid = '1';
1182	      -- last transfer
1183	      if beat = Beats then
1184	        StdlCompare(1, sm.rlast, "wrong RLAST");
1185	        -- check if last response is error (if error is expected) 
1186	        if not IgnoreResponse and Response /= xRESP_OKAY_c then
1187	          StdlvCompareStdlv(Response, sm.rresp, "wrong RRESP");
1188	        end if;
1189	      else
1190	        StdlCompare(0, sm.rlast, "wrong RLAST");
1191	      end if;
1192	      -- Check Data
1193	      DataStdlv_v := std_logic_vector(to_unsigned(DataCnt_v, DataStdlv_v'length));
1194	      if not IgnoreData then
1195	        StdlvCompareStdlv(DataStdlv_v, sm.rdata, "wrong RDATA");
1196	      end if;
1197	      DataCnt_v   := DataCnt_v + DataIncr;
1198	      -- Response must be OKAY for all beats (if okay is expected)
1199	      if not IgnoreResponse and Response = xRESP_OKAY_c then
1200	        StdlvCompareStdlv(Response, sm.rresp, "wrong RRESP");
1201	      end if;
1202	      -- Low cycles if required
1203	      if not (beat = Beats) then
1204	        for lc in 1 to RdyLowCycles loop
1205	          ms.rready <= '0';
1206	          wait until rising_edge(aclk) and sm.rvalid = '1';
1207	        end loop;
1208	        ms.rready <= '1';
1209	      end if;
1210	    end loop;
1211	    ms.rready <= '0';
1212	  end procedure;
1213	
1214	  procedure axi_expect_rresp_burst(Beats          : in natural;
1215	                                   DataStart      : in string;
1216	                                   DataIncr       : in string;
1217	                                   Base           : in integer;
1218	                                   Response       : in std_logic_vector(1 downto 0);
1219	                                   signal ms      : out axi_ms_r;
1220	                                   signal sm      : in axi_sm_r;
1221	                                   signal aclk    : in std_logic;
1222	                                   IgnoreData     : in boolean := false;
1223	                                   IgnoreResponse : in boolean := false;
1224	                                   RdyLowCycles   : in integer := 0) is
1225	    variable DataCntUnsign_v  : unsigned(ms.wdata'range);
1226	    variable DataIncrUnsign_v : unsigned(ms.wdata'range);
1227	    variable DataStdlv_v      : std_logic_vector(ms.wdata'range);
1228	  begin
1229	    ms.rready <= '1';
1230	    case Base is
1231	      when 10 =>
1232	        DataCntUnsign_v  := decimal_string_to_unsigned(DataStart, ms.wdata'length);
1233	        DataIncrUnsign_v := decimal_string_to_unsigned(DataIncr, ms.wdata'length);
1234	      when 16 =>
1235	        DataCntUnsign_v  := hex_string_to_unsigned(DataStart, ms.wdata'length);
1236	        DataIncrUnsign_v := hex_string_to_unsigned(DataIncr, ms.wdata'length);
1237	      when others =>
1238	        report "Procedure axi_expect_rresp_burst: unsupported base value" severity failure;
1239	    end case;
1240	    for beat in 1 to Beats loop
1241	      wait until rising_edge(aclk) and sm.rvalid = '1';
1242	      -- last transfer
1243	      if beat = Beats then
1244	        StdlCompare(1, sm.rlast, "wrong RLAST");
1245	        -- check if last response is error (if error is expected) 
1246	        if not IgnoreResponse and Response /= xRESP_OKAY_c then
1247	          StdlvCompareStdlv(Response, sm.rresp, "wrong RRESP");
1248	        end if;
1249	      else
1250	        StdlCompare(0, sm.rlast, "wrong RLAST");
1251	      end if;
1252	      -- Check Data
1253	      DataStdlv_v     := std_logic_vector(DataCntUnsign_v);
1254	      if not IgnoreData then
1255	        StdlvCompareStdlv(DataStdlv_v, sm.rdata, "wrong RDATA");
1256	      end if;
1257	      DataCntUnsign_v := DataCntUnsign_v + DataIncrUnsign_v;
1258	      -- Response must be OKAY for all beats (if okay is expected)
1259	      if not IgnoreResponse and Response = xRESP_OKAY_c then
1260	        StdlvCompareStdlv(Response, sm.rresp, "wrong RRESP");
1261	      end if;
1262	      -- Low cycles if required
1263	      if not (beat = Beats) then
1264	        for lc in 1 to RdyLowCycles loop
1265	          ms.rready <= '0';
1266	          wait until rising_edge(aclk) and sm.rvalid = '1';
1267	        end loop;
1268	        ms.rready <= '1';
